@page "/profile"
@rendermode InteractiveAuto
@attribute [Authorize]

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h3>Roles</h3>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == System.Security.Claims.ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<h1>Editor</h1>

<p>Welcome to the editor page. You have the <strong>Editor</strong> role.</p>

@page "/viewer"
@rendermode InteractiveAuto
@attribute [Authorize]

<h1>Viewer</h1>

<p>Welcome, @Username! This page is accessible to any authenticated user.</p>

@code {
    private string? Username;

    [CascadingParameter]
    private Task<AuthenticationState>? AuthState { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (AuthState is not null)
        {
            var state = await AuthState;
            Username = state.User.Identity?.Name;
        }
    }
}

